def find_average(numbers):
    if not numbers: 
        return 0
    total = 0
    for n in numbers:
        total += n
    return total / len(numbers)

result = find_average([])
print(result)

def is_prime(n):
    if n < 2:
        return False
    for i in range(2, int(n**0.5) + 1):
        if n % i == 0:
            return False
    return True

print(is_prime(1))  # Should print False — it does
print(is_prime(4))  # Should print False — it does  
print(is_prime(1000003))  # Takes forever

def celsius_to_fahrenheit(c):
    return c * 9 / 5 + 32

def fahrenheit_to_celsius(f):
    return (f - 32) * 5 / 9

print(fahrenheit_to_celsius(celsius_to_fahrenheit(100)))  # Should be 100, but isn't

def binary_search(arr, target):
    left, right = 0, len(arr) - 1
    while left <= right:
        mid = (left + right) // 2
        if arr[mid] == target:
            return mid
        elif arr[mid] < target:
            left = mid + 1
        else:
            right = mid - 1
    return -1

print(binary_search([1, 3, 5, 7, 9], 3))
